      },
      {
        "decision": "Middleware placement: before all authenticated routes",
        "implementation_note": "Rate limiting runs after authentication (so the API key is available) but before any business logic. Extract the API key from the auth context to use as the rate limit key."
      },
      {
        "decision": "Redis key TTL for automatic cleanup",
        "implementation_note": "Set a TTL of 60 seconds on each sorted set key so Redis automatically garbage-collects inactive keys. Re-set TTL on each request."
      },
      {
        "decision": "Fail-open on Redis failure",
        "implementation_note": "Wrap all Redis calls in try/catch. On any Redis error, allow the request through, log the error, and increment redis_unavailable_total counter. This must be explicitly unit-tested per Kobe's review."
      }
