        "criterion": "Fail-open on Redis outage",
        "given": "Redis is unavailable",
        "when": "Any request arrives",
        "then": "The request is allowed through, and redis_unavailable_total metric is incremented"
      },
      {
        "criterion": "Retry-After is dynamically computed",
        "given": "A request is rate-limited",
        "when": "The 429 response is constructed",
        "then": "Retry-After equals the number of seconds until the oldest request in the current window expires (not a fixed value)"
